INSERT INTO TEMPLATE_LICENSE (id, priority, license_type, template_text, license_name, details_url, is_spdx,
version)
SELECT id, priority, license_type, license_text, license_name, details_url, is_spdx, 1 FROM LICENSE;

INSERT INTO USAGE_LICENSE (id, template_id, version, software_component_id)
SELECT uuid_generate_v4(), id, 1, software_component_id
FROM LICENSE;
